use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    let MOD = 1_000_000_007;
    let mut y_counts = HashMap::new();
    for point in points {
        let y = point[1];
        *y_counts.entry(y).or_insert(0) += 1;
    }

    let mut S = 0;
    let mut sum_val_sq = 0;
    for cnt in y_counts.values() {
        let val = cnt * (cnt - 1) / 2;
        S = (S + val) % MOD;
        sum_val_sq = (sum_val_sq + val * val) % MOD;
    }

    let s_mod = S;
    let s_squared = (s_mod * s_mod) % MOD;
    let numerator = (s_squared - sum_val_sq) % MOD;

    let inv_2 = (MOD + 1) / 2;
    let ans = (numerator * inv_2) % MOD;

    ans
}
