        let term = (count * (count - 1)) % MOD;
        let term = term * inv_2 % MOD;
        S = (S + term) % MOD;
        let term_sq = term * term % MOD;
        sum_sq = (sum_sq + term_sq) % MOD;
    }

    let numerator = (S * S - sum_sq) % MOD;
    let ans = numerator * inv_2 % MOD;
    ans
}
